1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("Claim Office", () => {
5	  describe("quote — base premiums and fee", () => {
6	    it("returns 5 G for an empty item list (processing fee only)", () => {
7	      expect(quote({ items: [] })).toBe(5);
8	    });
9	    it("returns 105 G for a single plain sword (100 base + 5 fee)", () => {
10	      expect(quote({ items: [{ type: "sword" }] })).toBe(105);
11	    });
12	    it("returns 65 G for a single plain amulet (60 base + 5 fee)", () => {
13	      expect(quote({ items: [{ type: "amulet" }] })).toBe(65);
14	    });
15	    it("returns 85 G for a single plain staff (80 base + 5 fee)", () => {
16	      expect(quote({ items: [{ type: "staff" }] })).toBe(85);
17	    });
18	    it("returns 45 G for a single plain potion (40 base + 5 fee)", () => {
19	      expect(quote({ items: [{ type: "potion" }] })).toBe(45);
20	    });
21	    it("returns 30 G for a single rune (25 base + 5 fee)", () => {
22	      expect(quote({ items: [{ type: "rune" }] })).toBe(30);
23	    });
24	    it("returns 30 G for a single moonstone (25 base + 5 fee)", () => {
25	      expect(quote({ items: [{ type: "moonstone" }] })).toBe(30);
26	    });
27	  });
28	
29	  describe("quote — component building blocks", () => {
30	    it("returns 55 G for 2 runes (50 base + 5 fee)", () => {
31	      expect(quote({ items: [{ type: "rune" }, { type: "rune" }] })).toBe(55);
32	    });
33	    it("returns 65 G for 3 runes (60 base block + 5 fee)", () => {
34	      expect(
35	        quote({ items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }),
36	      ).toBe(65);
37	    });
38	    it("returns 105 G for 4 runes (100 base, no block + 5 fee)", () => {
39	      expect(
40	        quote({
41	          items: [
42	            { type: "rune" },
43	            { type: "rune" },
44	            { type: "rune" },
45	            { type: "rune" },
46	          ],
47	        }),
48	      ).toBe(105);
49	    });
50	    it("returns 180 G for 7 runes (175 base + 5 fee)", () => {
51	      expect(
52	        quote({
53	          items: [
54	            { type: "rune" },
55	            { type: "rune" },
56	            { type: "rune" },
57	            { type: "rune" },
58	            { type: "rune" },
59	            { type: "rune" },
60	            { type: "rune" },
61	          ],
62	        }),
63	      ).toBe(180);
64	    });
65	    it("returns 80 G for 2 runes + 1 moonstone (75 base, no block: different types + 5 fee)", () => {
66	      expect(
67	        quote({
68	          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
69	        }),
70	      ).toBe(80);
71	    });
72	    it("returns 125 G for 3 runes + 3 moonstones (120 base, two separate blocks + 5 fee)", () => {
73	      expect(
74	        quote({
75	          items: [
76	            { type: "rune" },
77	            { type: "rune" },
78	            { type: "rune" },
79	            { type: "moonstone" },
80	            { type: "moonstone" },
81	            { type: "moonstone" },
82	          ],
83	        }),
84	      ).toBe(125);
85	    });
86	  });
87	
88	  describe("quote — item-specific modifiers", () => {
89	    it("adds 50% curse surcharge to a cursed sword's base premium", () => {
90	      expect(quote({ items: [{ type: "sword", cursed: true }] })).toBe(155);
91	    });
92	    it("adds 30% high-enchantment surcharge to a sword with enchantment exactly 5", () => {
93	      expect(quote({ items: [{ type: "sword", enchantment: 5 }] })).toBe(135);
94	    });
95	    it("does not add high-enchantment surcharge to a sword with enchantment 4", () => {
96	      expect(quote({ items: [{ type: "sword", enchantment: 4 }] })).toBe(105);
97	    });
98	    it("applies both curse and high-enchantment surcharges to a cursed sword with enchantment 5", () => {
99	      expect(
100	        quote({ items: [{ type: "sword", cursed: true, enchantment: 5 }] }),
101	      ).toBe(185);
102	    });
103	  });
104	
105	  describe("quote — policy-wide modifiers", () => {
106	    it("applies 20% loyalty discount for a customer with exactly 2 years with MHPCO", () => {
107	      expect(
108	        quote({ customer: { yearsWithMHPCO: 2 }, items: [{ type: "sword" }] }),
109	      ).toBe(85);
110	    });
111	    it("does not apply loyalty discount for a customer with fewer than 2 years", () => {
112	      expect(
113	        quote({ customer: { yearsWithMHPCO: 1 }, items: [{ type: "sword" }] }),
114	      ).toBe(105);
115	    });
116	    it("applies 10% first-insurance surcharge to each item in a quote regardless of history", () => {
117	      expect(
118	        quote({
119	          customer: { yearsWithMHPCO: 0, previousContracts: 0 },
120	          items: [{ type: "sword" }],
121	        }),
122	      ).toBe(115);
123	    });
124	    it("applies 15% follow-up discount on the customer's second quote in a scenario", () => {
125	      // First-insurance still applies on a follow-up contract per the spec
126	      // ("each item in a quote is treated as a first insurance, regardless of
127	      // customer history"): 100 base + 10 first-insurance − 15 follow-up
128	      // + 5 fee = 100.
129	      expect(
130	        quote({
131	          customer: { yearsWithMHPCO: 0, previousContracts: 1 },
132	          items: [{ type: "sword" }],
133	        }),
134	      ).toBe(100);
135	    });
136	  });
137	
138	  describe("quote — modifier scope on multi-item policies", () => {
139	    it("sums item base premiums into the policy base premium for a cursed sword and a plain amulet", () => {
140	      expect(
141	        quote({ items: [{ type: "sword", cursed: true }, { type: "amulet" }] }),
142	      ).toBe(215);
143	    });
144	    it("applies the curse surcharge to only the cursed item's base premium, not the policy total", () => {
145	      // sword base 100 + amulet base 60 = policy base 160.
146	      // Curse surcharge is 50% of the cursed sword's base (50), NOT 50% of
147	      // the policy total (which would be 80). So 160 + 50 + 5 fee = 215.
148	      // The policy-total interpretation would yield 160 + 80 + 5 = 245.
149	      expect(
150	        quote({ items: [{ type: "sword", cursed: true }, { type: "amulet" }] }),
151	      ).toBe(215);
152	    });
153	  });
154	
155	  describe("quote — rounding", () => {
156	    it("rounds the final premium up to whole G (197.5 → 198)", () => {
157	      // Loyal customer (2 years) with a single high-enchantment rune:
158	      // base 25 - loyalty 25*0.2 (5) + high-ench 25*0.3 (7.5) + 5 fee = 32.5
159	      // The unrounded premium 32.5 must round UP to 33 (in MHPCO's favour).
160	      expect(
161	        quote({
162	          customer: { yearsWithMHPCO: 2 },
163	          items: [{ type: "rune", enchantment: 5 }],
164	        }),
165	      ).toBe(33);
166	    });
167	  });
168	
169	  describe("quote — integration examples", () => {
170	    it("returns 165 G for a newcomer's cursed steel sword at enchantment 3", () => {
171	      expect(
172	        quote({
173	          customer: { yearsWithMHPCO: 0, previousContracts: 0 },
174	          items: [
175	            { type: "sword", material: "steel", enchantment: 3, cursed: true },
176	          ],
177	        }),
178	      ).toBe(165);
179	    });
180	    it("returns 160 G for a long-standing customer's second-quote cursed steel sword at enchantment 7", () => {
181	      expect(
182	        quote({
183	          customer: { yearsWithMHPCO: 3, previousContracts: 1 },
184	          items: [
185	            { type: "sword", material: "steel", enchantment: 7, cursed: true },
186	          ],
187	        }),
188	      ).toBe(160);
189	    });
190	  });
191	
192	  describe("claim — standard reimbursement and deductible", () => {
193	    it("pays 400 G for a steel sword enchantment 3 with 500 G damage (full minus 100 deductible)", () => {
194	      expect(
195	        claim({
196	          items: [{ type: "sword", material: "steel", enchantment: 3 }],
197	          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 500 }] },
198	        }).payout,
199	      ).toBe(400);
200	    });
201	    it.todo("pays 100 G for a rune with 200 G damage (full minus 100 deductible)");
202	    it.todo("applies the 100 G deductible once per damaged item (sword 500 + amulet 300 → 600)");
203	  });
204	
205	  describe("claim — special clauses", () => {
206	    it.todo("reimburses 50% before deductible for a steel sword at enchantment 9 with 1000 G damage (→ 400)");
207	    it.todo("fully reimburses before deductible for a dragon sword at enchantment 5 with 800 G damage (→ 700)");
208	    it.todo("applies the 50% rule over dragon material for a dragon sword at enchantment 9 with 1000 G damage (→ 400)");
209	    it.todo("applies the high-enchantment clause for a dragon sword at exactly enchantment 8 with 1000 G damage (→ 400)");
210	  });
211	
212	  describe("claim — cap", () => {
213	    it.todo("caps total payout at twice the unmodified insurance sum");
214	    it.todo("reduces a claim to the remaining cap and reports remainingCap across successive claims (1500 → 1400 then 600)");
215	  });
216	
217	  describe("claim — rounding", () => {
218	    it.todo("rounds the final payout down to whole G (350.5 → 350)");
219	  });
220	});
